label_join(
  sum(
    rate(container_cpu_usage_seconds_total{
      namespace=~"$namespace",
      pod=~"$component.*",
      pod=~"$pod",
      container=~"$container",
      image!~"registry.k8s.io/pause:3.10", 
      id=~".*.scope",
      pod!~"",
      container!~"" 
    }[$__rate_interval])
  ) by (pod, container, namespace, node)
  /
  sum(
    kube_pod_container_resource_limits{
      resource=~"cpu",
      namespace=~"$namespace",
      pod=~"$component.*",
      pod=~"$pod",
      container=~"$container",
      pod!~"",
      container!~"" 
    }
  ) by (pod, container, namespace, node),
  "podcontainer",
  ":",
  "pod",
  "container"
)

